const state = $('Read State').first().json.content || '';
const plan = $('Read Weekly Plan').first().json.content || '';
const supportLog = $('Read Support Log').first().json.content || 'No support tickets yet.';

return [{
  json: {
    businessId: 'bayflow',
    businessPath: 'memory-bank/businesses/bayflow',
    prompt: `Today is ${new Date().toISOString().split('T')[0]}. You are the Product Agent for BayFlow (auto repair shop software).

Your responsibilities: engineering priorities, SEO infrastructure maintenance, error monitoring, executing weekly plan product tasks, and support-driven iteration.

## Current State
${state}

## Weekly Plan
${plan}

## Recent Support Tickets
${supportLog}

Perform your weekly product review:

1. **Weekly Plan Execution:** Review Product Agent tasks from the weekly plan. What needs to be done? Prioritize.

2. **Support-Driven Iteration:** Review support tickets. Any bugs tagged? Any feature requests appearing 3+ times? Any UX confusion patterns? Recommend what to build/fix.

3. **SEO Infrastructure Check:** Is the blog CMS working? Sitemap up to date? Structured data valid? Meta tags present on all pages? Any broken links?

4. **Error Monitoring:** Any Sentry errors to investigate? Any endpoint with >5 errors (auto-fix trigger)?

5. **Quality Gate:** Does the product pass the pre-launch quality gate? (Functional product, professional landing page, working payment flow, monitoring active)

6. **GitHub Issues to Create:** For each actionable item, output a GitHub issue title and body that Claude Code can pick up via GitHub Actions.

Output your report in the structured format: Agent name, business, date, status (GREEN/YELLOW/RED), key metrics, actions taken, issues detected, recommendations, needs from CEO Agent.

Then output a section called ## GitHub Issues with each issue formatted as:
### Issue: [title]
[body description with acceptance criteria]`
  }
}];

const response = $json.response.text;
const businessId = $('Build Product Prompt').first().json.businessId;
const businessPath = $('Build Product Prompt').first().json.businessPath;

// Extract GitHub issues from the response
const issueRegex = /### Issue: (.+?)\n([\s\S]*?)(?=### Issue:|$)/g;
const issues = [];
let match;
while ((match = issueRegex.exec(response)) !== null) {
  issues.push({
    title: match[1].trim(),
    body: match[2].trim()
  });
}

return [{
  json: {
    report: response,
    issues,
    businessId,
    businessPath
  }
}];

// Create GitHub issues in the business app repo for Claude Code to pick up
const issues = $('Parse GitHub Issues').first().json.issues;
if (!issues || issues.length === 0) {
  return [{ json: { message: 'No issues to create' } }];
}

// Return issues as separate items for the GitHub node to process
return issues.map(issue => ({
  json: {
    title: `[Product Agent] ${issue.title}`,
    body: `${issue.body}\n\n---\n_Auto-generated by Product Agent on ${new Date().toISOString().split('T')[0]}_`
  }
}));
